// And groups predicates with the AND operator between them.
func And(predicates ...predicate.TodoCandidate) predicate.TodoCandidate {
	return predicate.TodoCandidate(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.TodoCandidate) predicate.TodoCandidate {
	return predicate.TodoCandidate(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.TodoCandidate) predicate.TodoCandidate {
	return predicate.TodoCandidate(sql.NotPredicates(p))
}
